use thiserror::Error;

pub type Result<T> = std::result::Result<T, MyError>;

#[derive(Error, Debug)]
pub enum MyError {
    #[error("IO error: {0}")]
    Io(String),

    #[error("Parse error: {0}")]
    Parse(String),

    #[error("Serialization error: {0}")]
    Serialization(#[from] serde_json::Error),
}

use adapteros_core::{AosError, Result};

pub async fn process_data(&self, data: &[u8]) -> Result<ProcessedData> {
    let parsed = parse_data(data)
        .await
        .map_err(|e| AosError::Parse(format!("Failed to parse data: {}", e)))?;

    let validated = validate_data(&parsed)
        .await
        .map_err(|e| AosError::Validation(format!("Validation failed: {}", e)))?;

    Ok(ProcessedData::new(validated))
}

