pub struct DataProcessor {
    config: Arc<Config>,
    cache: RwLock<HashMap<String, Arc<CachedData>>>,
}

impl DataProcessor {
    pub fn new(config: Config) -> Self {
        Self {
            config: Arc::new(config),
            cache: RwLock::new(HashMap::new()),
        }
    }

    pub async fn get_data(&self, key: &str) -> Result<Arc<CachedData>> {
        // Read from cache first
        if let Some(data) = self.cache.read().await.get(key) {
            return Ok(data.clone());
        }

        // Compute and cache
        let data = self.compute_data(key).await?;
        let data = Arc::new(data);

        self.cache.write().await.insert(key.to_string(), data.clone());
        Ok(data)
    }
}

pub struct ItemCollection {
    items: Vec<Arc<Item>>,
}

impl ItemCollection {
    pub fn new() -> Self {
        Self {
            items: Vec::new(),
        }
    }

    pub fn add(&mut self, item: Item) {
        self.items.push(Arc::new(item));
    }

    pub fn get(&self, index: usize) -> Option<&Arc<Item>> {
        self.items.get(index)
    }

    pub fn iter(&self) -> impl Iterator<Item = &Arc<Item>> {
        self.items.iter()
    }

    pub fn find_by_name(&self, name: &str) -> Option<&Arc<Item>> {
        self.items.iter().find(|item| item.name == name)
    }
}

use tokio::spawn;
use tracing::{error, info};

pub async fn start_background_processing(&self) -> Result<()> {
    let handle = spawn(async move {
        if let Err(e) = self.process_continuously().await {
            error!(error = %e, "Background task failed");
            // Don't panic - log and continue
        }
    });

    // Store handle for potential cancellation
    self.task_handles.write().await.push(handle);

    info!("Started background processing task");
    Ok(())
}

async fn process_continuously(&self) -> Result<()> {
    loop {
        tokio::time::sleep(Duration::from_secs(60)).await;
        self.perform_maintenance().await?;
    }
}

use std::sync::Arc;
use tokio::sync::RwLock;

// Thread-safe data structure
#[derive(Clone)]
pub struct SharedState {
    inner: Arc<RwLock<StateInner>>,
}

struct StateInner {
    counter: u64,
    data: HashMap<String, Vec<u8>>,
}

// Safety: RwLock provides interior mutability
unsafe impl Send for SharedState {}
unsafe impl Sync for SharedState {}

impl SharedState {
    pub fn new() -> Self {
        Self {
            inner: Arc::new(RwLock::new(StateInner {
                counter: 0,
                data: HashMap::new(),
            })),
        }
    }

    pub async fn increment(&self) -> u64 {
        let mut inner = self.inner.write().await;
        inner.counter += 1;
        inner.counter
    }
}

use adapteros_core::Result;

pub async fn complex_operation(&self, config_path: &Path) -> Result<Output> {
    // Load configuration
    let config_bytes = std::fs::read(config_path)
        .map_err(|e| AosError::Io(format!("Failed to read config: {}", e)))?;

    let config: Config = serde_json::from_slice(&config_bytes)
        .map_err(|e| AosError::Parse(format!("Invalid config: {}", e)))?;

    // Validate configuration
    self.validate_config(&config)?;

    // Process data
    let data = self.load_data(&config.data_path).await?;
    let processed = self.process_data(&data, &config).await?;

    // Final validation
    self.final_validation(&processed)?;

    Ok(Output::new(processed))
}

