            rank: self.rank,
            alpha: self.alpha,
            learning_rate: self.learning_rate,
            batch_size: self.batch_size,
            epochs: self.epochs,
        })
    }
}

use std::sync::Arc;
use tokio::sync::Mutex;

pub struct ResourcePool<T> {
    resources: Arc<Mutex<Vec<T>>>,
    max_size: usize,
}

impl<T> ResourcePool<T> {
    pub fn new(max_size: usize) -> Self {
        Self {
            resources: Arc::new(Mutex::new(Vec::new())),
            max_size,
        }
    }

    pub async fn acquire(&self) -> Result<PoolGuard<T>> {
        let mut resources = self.resources.lock().await;

        if resources.is_empty() {
            if resources.len() < self.max_size {
                // Create new resource
                let resource = self.create_resource().await?;
                resources.push(resource);
            } else {
                return Err(AosError::Resource("Pool exhausted".to_string()));
            }
        }

        let resource = resources.pop().unwrap();
        Ok(PoolGuard {
            resource: Some(resource),
            pool: self.resources.clone(),
        })
    }
}

pub struct PoolGuard<T> {
    resource: Option<T>,
    pool: Arc<Mutex<Vec<T>>>,
}

impl<T> Drop for PoolGuard<T> {
    fn drop(&mut self) {
        if let Some(resource) = self.resource.take() {
            let pool = self.pool.clone();
            tokio::spawn(async move {
                pool.lock().await.push(resource);
            });
        }
    }
}
